    def test_init_with_options(self):
        options = MagicMock()
        options.model = MockModel
        options.fields = ['name', 'age']
        options.exclude = ['bio']
        options.widgets = {'name': widgets.TextInput()}
        options.localized_fields = ['name']
        options.labels = {'name': 'Full Name'}
        options.help_texts = {'name': 'Enter your full name'}
        options.error_messages = {'name': {'required': 'Name is required'}}
        options.field_classes = {'name': fields.CharField}

