import unittest
from unittest.mock import Mock, MagicMock, patch
from collections import defaultdict
from itertools import chain

from django.conf import settings
from django.db import models
from django.db.migrations import operations
from django.db.migrations.migration import Migration
from django.db.migrations.operations.models import AlterModelOptions
from django.db.migrations.autodetector import MigrationAutodetector
from django.db.migrations.questioner import MigrationQuestioner
from django.db.migrations.utils import RegexObject
from django.utils.topological_sort import stable_topological_sort

class TestMigrationAutodetector(unittest.TestCase):
    def setUp(self):
        self.from_state = Mock()
        self.to_state = Mock()
        self.questioner = Mock(spec=MigrationQuestioner)
        self.autodetector = MigrationAutodetector(
            self.from_state, self.to_state, self.questioner
        )

    def test_init(self):
        self.assertEqual(self.autodetector.from_state, self.from_state)
        self.assertEqual(self.autodetector.to_state, self.to_state)
        self.assertEqual(self.autodetector.questioner, self.questioner)
        self.assertEqual(self.autodetector.existing_apps, set())

    def test_deep_deconstruct_list(self):
        obj = [1, 2, 3]
        result = self.autodetector.deep_deconstruct(obj)
        self.assertEqual(result, [1, 2, 3])

    def test_deep_deconstruct_tuple(self):
        obj = (1, 2, 3)
        result = self.autodetector.deep_deconstruct(obj)
        self.assertEqual(result, (1, 2, 3))

    def test_deep_deconstruct_dict(self):
        obj = {'a': 1, 'b': 2}
        result = self.autodetector.deep_deconstruct(obj)
        self.assertEqual(result, {'a': 1, 'b': 2})

    def test_deep_deconstruct_partial(self):
        obj = functools.partial(lambda x: x, 1, y=2)
        result = self.autodetector.deep_deconstruct(obj)
        self.assertEqual(result[0], obj.func)
        self.assertEqual(result[1], (1,))
        self.assertEqual(result[2], {'y': 2})

    def test_deep_deconstruct_regex(self):
        import re
        obj = re.compile(r'test')
        result = self.autodetector.deep_deconstruct(obj)
        self.assertIsInstance(result, RegexObject)

    def test_deep_deconstruct_type(self):
        obj = str
        result = self.autodetector.deep_deconstruct(obj)
        self.assertEqual(result, str)

    def test_deep_deconstruct_deconstructible(self):
        field = models.CharField(max_length=10)
        result = self.autodetector.deep_deconstruct(field)
        self.assertEqual(result[0], 'django.db.models.fields.CharField')
        self.assertEqual(result[1], [])
        self.assertEqual(result[2]['max_length'], 10)

    def test_only_relation_agnostic_fields(self):
        fields = {
            'field1': models.CharField(max_length=10),
